public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog and the fox was very quick indeed " +
        "so the dog decided to rest under the old oak tree while the birds sang their beautiful songs " +
        "in the warm summer breeze that gently swept across the green meadow where flowers bloomed " +
        "with vibrant colors of red blue yellow and purple attracting butterflies and bees from miles around " +
        "the children played happily in the park running jumping and laughing without a care in the world " +
        "as the sun slowly set behind the distant mountains casting long shadows over the peaceful valley below";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

